        }
    }
    
    auto result = ide->getChainOfThought()->generateChain(goal, context);
    if (!result) {
        return std::unexpected(CLIError::ExecutionFailed);
    }
    
    auto explanation = ide->getChainOfThought()->generateExplanation(result.value());
    if (!explanation) {
        return std::unexpected(CLIError::ExecutionFailed);
