int main(int argc, char* argv[]) {
    CLI::App app{"RawrXD v3.0 - Complete Agentic IDE"};
    
    // Mode selection
    std::string mode = "cli";
    app.add_option("-m,--mode", mode, "Mode: cli, gui, server")
        ->default_val("cli")
        ->check(CLI::IsMember({"cli", "gui", "server"}));
    
    // Configuration
    std::string configPath = "./config.json";
    app.add_option("-c,--config", configPath, "Configuration file path");
    
    // Model path
    std::string modelPath;
    app.add_option("-m,--model", modelPath, "Model file or directory path");
    
    // Logging
    std::string logLevel = "info";
    app.add_option("-l,--log-level", logLevel, "Log level: trace, debug, info, warn, error")
        ->default_val("info")
        ->check(CLI::IsMember({"trace", "debug", "info", "warn", "error"}));
    
    // Features
    bool enableSwarm = true;
    app.add_flag("--swarm", enableSwarm, "Enable swarm intelligence");
    
    bool enableChain = true;
    app.add_flag("--chain", enableChain, "Enable chain-of-thought");
    
    bool enableLSP = true;
    app.add_flag("--lsp", enableLSP, "Enable Language Server Protocol");
    
    bool headless = false;
    app.add_flag("--headless", headless, "Run in headless mode");
    
    CLI11_PARSE(app, argc, argv);
    
    // Setup logging
    spdlog::set_level(spdlog::level::from_str(logLevel));
    spdlog::set_pattern("[%Y-%m-%d %H:%M:%S.%e] [%^%l%$] %v");
    
    // Create IDE config
    IDEConfig config;
    config.logLevel = logLevel;
    config.enableSwarm = enableSwarm;
    config.enableChainOfThought = enableChain;
    config.enableLSP = enableLSP;
    
    // Load config from file if exists
    if (std::filesystem::exists(configPath)) {
        std::ifstream file(configPath);
        json j;
        file >> j;
        
        config.modelsPath = j.value("models_path", "./models");
        config.toolsPath = j.value("tools_path", "./tools");
        config.maxWorkers = j.value("max_workers", 8);
        config.maxMemoryMB = j.value("max_memory_mb", 16384);
        config.enableNetwork = j.value("enable_network", true);
        config.apiKey = j.contains("api_key") ? std::optional<std::string>{j["api_key"]} : std::nullopt;
    }
    
    // Override with CLI args
    if (!modelPath.empty()) {
        config.modelsPath = modelPath;
    }
    
    // Create IDE manager
    auto& manager = IDEManager::instance();
    
    // Create IDE instance
    auto ideResult = manager.createIDE(config);
    if (!ideResult) {
        std::cerr << "Failed to create IDE: " << static_cast<int>(ideResult.error()) << std::endl;
        return 1;
    }
    
    auto ide = ideResult.value();
    
    // Run based on mode
    if (mode == "cli") {
        // Create CLI
        EnhancedCLI cli;
        
        // Register IDE commands
        cli.registerCommand({
            "status",
            "Show IDE status",
            {"st", "info"},
            [ide](const std::vector<std::string>& args, IDEOrchestrator*) {
                return std::expected<std::string, CLIError>(ide->getStatus().dump(2));
            },
            "status",
            "Display current IDE status and metrics",
            true
        });
        
        cli.registerCommand({
            "generate",
            "Generate using IDE inference engine",
            {"gen", "g"},
            [ide](const std::vector<std::string>& args, IDEOrchestrator*) {
                if (args.empty()) {
                    return std::expected<std::string, CLIError>(
                        std::unexpected(CLIError::InvalidArguments)
                    );
                }
                
                auto result = ide->generateCode(args[0]);
                if (!result) {
                    return std::expected<std::string, CLIError>(
                        std::unexpected(CLIError::ExecutionFailed)
                    );
                }
                
                return result.value();
            },
            "generate <prompt>",
            "Generate code using the IDE's inference engine",
            true
        });
        
        cli.registerCommand({
            "swarm",
            "Execute with swarm intelligence",
            {"sw", "multi"},
            [ide](const std::vector<std::string>& args, IDEOrchestrator*) {
                if (args.empty()) {
                    return std::expected<std::string, CLIError>(
                        std::unexpected(CLIError::InvalidArguments)
                    );
                }
                
                std::string task = std::accumulate(args.begin(), args.end(), std::string(),
                    [](const std::string& a, const std::string& b) {
                        return a.empty() ? b : a + " " + b;
                    });
                
                auto result = ide->getSwarm()->executeTask(task);
                if (!result) {
                    return std::expected<std::string, CLIError>(
                        std::unexpected(CLIError::ExecutionFailed)
                    );
                }
                
                return std::format("Swarm consensus: {}\nConfidence: {:.2f}", 
                    result->consensus, result->confidence);
            },
            "swarm <task>",
            "Execute task using swarm intelligence",
            true
        });
        
        // Run CLI
        return cli.runInteractive(ide.get()) ? 0 : 1;
        
    } else if (mode == "gui") {
        // Create GUI
        GUIMain gui;
        
        auto result = gui.initialize(GetModuleHandle(nullptr));
        if (!result) {
            std::cerr << "GUI initialization failed: " << result.error() << std::endl;
            return 1;
        }
        
        return gui.run() ? 0 : 1;
        
    } else if (mode == "server") {
        // Create HTTP server
        auto server = std::make_unique<GGUFAlpacaServer>(11434);
        
        // Add IDE endpoints
        server->addEndpoint("/api/ide/status", [ide](const json& req) {
            return ide->getStatus();
        });
        
        server->addEndpoint("/api/ide/generate", [ide](const json& req) {
            std::string prompt = req.value("prompt", "");
            auto result = ide->generateCode(prompt);
            if (result) {
                return json{{"response", result.value()}};
            }
            return json{{"error", "Generation failed"}};
        });
        
        server->addEndpoint("/api/ide/swarm", [ide](const json& req) {
            std::string task = req.value("task", "");
            auto result = ide->getSwarm()->executeTask(task);
            if (result) {
                return json{
                    {"consensus", result->consensus},
                    {"confidence", result->confidence},
                    {"supporting_agents", result->supportingAgents}
                };
            }
            return json{{"error", "Swarm execution failed"}};
        });
        
        server->addEndpoint("/api/ide/chain", [ide](const json& req) {
            std::string goal = req.value("goal", "");
            auto context = req.value("context", json::object());
            std::unordered_map<std::string, std::string> contextMap;
            for (auto& [key, value] : context.items()) {
                contextMap[key] = value.get<std::string>();
            }
            
            auto result = ide->getChainOfThought()->generateChain(goal, contextMap);
            if (result) {
                return json{
                    {"steps", result->steps.size()},
                    {"confidence", result->overallConfidence},
                    {"complete", result->isComplete}
                };
            }
            return json{{"error", "Chain generation failed"}};
        });
        
        // Add tokenization endpoints
        server->addEndpoint("/api/tokenize", [ide](const json& req) {
            std::string text = req.value("text", "");
            auto result = ide->getTokenizer()->encode(text);
            if (result) {
                return json{{"tokens", result.value()}};
            }
            return json{{"error", "Tokenization failed"}};
        });
        
        server->addEndpoint("/api/detokenize", [ide](const json& req) {
            std::vector<int> tokens = req.value("tokens", std::vector<int>());
            auto result = ide->getTokenizer()->decode(tokens);
            if (result) {
                return json{{"text", result.value()}};
            }
            return json{{"error", "Detokenization failed"}};
        });
        
        spdlog::info("Starting HTTP server on port 11434");
        server->run();
        
        return 0;
    }
    
    return 0;
}
